const ethers = require('ethers');

// Configuration
const NETWORK_CONFIG = {
  mainnet: {
    rpcUrl: 'https://mainnet.infura.io/v3/YOUR_INFURA_KEY',
    chainId: 1
  },
  goerli: {
    rpcUrl: 'https://goerli.infura.io/v3/YOUR_INFURA_KEY',
    chainId: 5
  },
  sepolia: {
    rpcUrl: 'https://sepolia.infura.io/v3/YOUR_INFURA_KEY',
    chainId: 11155111
  },
  localhost: {
    rpcUrl: 'http://127.0.0.1:8545',
    chainId: 31337
  }
};

class Web3Service {
  constructor(network = 'localhost') {
    this.provider = new ethers.JsonRpcProvider(NETWORK_CONFIG[network].rpcUrl);
    this.network = network;
    this.wallets = new Map();
  }

  addWallet(name, privateKey) {
    const wallet = new ethers.Wallet(privateKey, this.provider);
    this.wallets.set(name, wallet);
    return wallet.address;
  }

  getWallet(name) {
    return this.wallets.get(name);
  }

  async getBalance(address) {
    const balance = await this.provider.getBalance(address);
    return ethers.formatEther(balance);
  }

  async sendETH(fromWalletName, toAddress, amountInEther) {
    const wallet = this.getWallet(fromWalletName);
    if (!wallet) {
      throw new Error(`Wallet ${fromWalletName} not found`);
    }

    const tx = {
      to: toAddress,
      value: ethers.parseEther(amountInEther.toString())
    };

    const transaction = await wallet.sendTransaction(tx);
    const receipt = await transaction.wait();
    
    return {
      transactionHash: receipt.hash,
      blockNumber: receipt.blockNumber,
      gasUsed: receipt.gasUsed.toString(),
      status: receipt.status
    };
  }

  async sendETHWithGasLimit(fromWalletName, toAddress, amountInEther, gasLimit) {
    const wallet = this.getWallet(fromWalletName);
    if (!wallet) {
      throw new Error(`Wallet ${fromWalletName} not found`);
    }

    const tx = {
      to: toAddress,
      value: ethers.parseEther(amountInEther.toString()),
      gasLimit: gasLimit
    };

    const transaction = await wallet.sendTransaction(tx);
    const receipt = await transaction.wait();
    
    return {
      transactionHash: receipt.hash,
      blockNumber: receipt.blockNumber,
      gasUsed: receipt.gasUsed.toString(),
      status: receipt.status
    };
  }

  async deployContract(walletName, abi, bytecode, constructorArgs = []) {
    const wallet = this.getWallet(walletName);
    if (!wallet) {
      throw new Error(`Wallet ${walletName} not found`);
    }

    const factory = new ethers.ContractFactory(abi, bytecode, wallet);
    const contract = await factory.deploy(...constructorArgs);
    await contract.waitForDeployment();
    
    const address = await contract.getAddress();
    
    return {
      contractAddress: address,
      deploymentHash: contract.deploymentTransaction().hash
    };
  }

  getContract(contractAddress, abi, walletName = null) {
    if (walletName) {
      const wallet = this.getWallet(walletName);
      if (!wallet) {
        throw new Error(`Wallet ${walletName} not found`);
      }
      return new ethers.Contract(contractAddress, abi, wallet);
    }
    return new ethers.Contract(contractAddress, abi, this.provider);
  }

  async callContractMethod(contractAddress, abi, methodName, args = [], walletName = null) {
    const contract = this.getContract(contractAddress, abi, walletName);
    const result = await contract[methodName](...args);
    return result;
  }

  async sendContractTransaction(contractAddress, abi, walletName, methodName, args = [], options = {}) {
    const wallet = this.getWallet(walletName);
    if (!wallet) {
      throw new Error(`Wallet ${walletName} not found`);
    }

    const contract = new ethers.Contract(contractAddress, abi, wallet);
    
    const txOptions = {};
    if (options.value) {
      txOptions.value = ethers.parseEther(options.value.toString());
    }
    if (options.gasLimit) {
      txOptions.gasLimit = options.gasLimit;
    }

    const tx = await contract[methodName](...args, txOptions);
    const receipt = await tx.wait();
    
    return {
      transactionHash: receipt.hash,
      blockNumber: receipt.blockNumber,
      gasUsed: receipt.gasUsed.toString(),
      status: receipt.status,
      logs: receipt.logs
    };
  }

  async estimateGas(contractAddress, abi, methodName, args = [], fromWalletName = null, value = null) {
    let contract;
    if (fromWalletName) {
      const wallet = this.getWallet(fromWalletName);
      contract = new ethers.Contract(contractAddress, abi, wallet);
    } else {
      contract = new ethers.Contract(contractAddress, abi, this.provider);
    }

    const options = {};
    if (value) {
      options.value = ethers.parseEther(value.toString());
    }

    const gasEstimate = await contract[methodName].estimateGas(...args, options);
    return gasEstimate.toString();
  }

  async getTransactionReceipt(txHash) {
    const receipt = await this.provider.getTransactionReceipt(txHash);
    if (!receipt) {
      return null;
    }
    
    return {
      transactionHash: receipt.hash,
      blockNumber: receipt.blockNumber,
      gasUsed: receipt.gasUsed.toString(),
      status: receipt.status,
      from: receipt.from,
      to: receipt.to,
      logs: receipt.logs
    };
  }

  async getTransaction(txHash) {
    const tx = await this.provider.getTransaction(txHash);
    if (!tx) {
      return null;
    }
    
    return {
      hash: tx.hash,
      from: tx.from,
      to: tx.to,
      value: ethers.formatEther(tx.value),
      gasLimit: tx.gasLimit.toString(),
      gasPrice: tx.gasPrice ? ethers.formatUnits(tx.gasPrice, 'gwei') : null,
      nonce: tx.nonce,
      data: tx.data,
      chainId: tx.chainId
    };
  }

  async getCurrentGasPrice() {
    const feeData = await this.provider.getFeeData();
    return {
      gasPrice: feeData.gasPrice ? ethers.formatUnits(feeData.gasPrice, 'gwei') : null,
      maxFeePerGas: feeData.maxFeePerGas ? ethers.formatUnits(feeData.maxFeePerGas, 'gwei') : null,
      maxPriorityFeePerGas: feeData.maxPriorityFeePerGas ? ethers.formatUnits(feeData.maxPriorityFeePerGas, 'gwei') : null
    };
  }

  async getBlockNumber() {
    return await this.provider.getBlockNumber();
  }

  async getBlock(blockNumber) {
    const block = await this.provider.getBlock(blockNumber);
    return {
      number: block.number,
      hash: block.hash,
      timestamp: block.timestamp,
      transactions: block.transactions,
      miner: block.miner
    };
  }

  async signMessage(walletName, message) {
    const wallet = this.getWallet(walletName);
    if (!wallet) {
      throw new Error(`Wallet ${walletName} not found`);
    }
    return await wallet.signMessage(message);
  }

  async verifyMessage(message, signature) {
    return ethers.verifyMessage(message, signature);
  }

  async sendERC20Token(contractAddress, abi, walletName, toAddress, amount, decimals = 18) {
    const wallet = this.getWallet(walletName);
    if (!wallet) {
      throw new Error(`Wallet ${walletName} not found`);
    }

    const contract = new ethers.Contract(contractAddress, abi, wallet);
    const amountInWei = ethers.parseUnits(amount.toString(), decimals);
    
    const tx = await contract.transfer(toAddress, amountInWei);
    const receipt = await tx.wait();
    
    return {
      transactionHash: receipt.hash,
      blockNumber: receipt.blockNumber,
      gasUsed: receipt.gasUsed.toString(),
      status: receipt.status
    };
  }

  async getERC20Balance(contractAddress, abi, holderAddress) {
    const contract = new ethers.Contract(contractAddress, abi, this.provider);
    const balance = await contract.balanceOf(holderAddress);
    const decimals = await contract.decimals();
    return ethers.formatUnits(balance, decimals);
  }

  async approveERC20(contractAddress, abi, walletName, spenderAddress, amount, decimals = 18) {
    const wallet = this.getWallet(walletName);
    if (!wallet) {
      throw new Error(`Wallet ${walletName} not found`);
    }

    const contract = new ethers.Contract(contractAddress, abi, wallet);
    const amountInWei = ethers.parseUnits(amount.toString(), decimals);
    
    const tx = await contract.approve(spenderAddress, amountInWei);
    const receipt = await tx.wait();
    
    return {
      transactionHash: receipt.hash,
      blockNumber: receipt.blockNumber,
      gasUsed: receipt.gasUsed.toString(),
      status: receipt.status
    };
  }

  async getNonce(address) {
    return await this.provider.getTransactionCount(address);
  }

  async waitForTransaction(txHash, confirmations = 1) {
    const receipt = await this.provider.waitForTransaction(txHash, confirmations);
    return {
      transactionHash: receipt.hash,
      blockNumber: receipt.blockNumber,
      gasUsed: receipt.gasUsed.toString(),
      status: receipt.status
    };
  }

  createRandomWallet() {
    const wallet = ethers.Wallet.createRandom();
    return {
      address: wallet.address,
      privateKey: wallet.privateKey,
      mnemonic: wallet.mnemonic.phrase
    };
  }

  walletFromMnemonic(mnemonic, index = 0) {
    const wallet = ethers.Wallet.fromPhrase(mnemonic);
    const derivedWallet = wallet.deriveChild(index);
    return {
      address: derivedWallet.address,
      privateKey: derivedWallet.privateKey
    };
  }

  async sendBatchTransactions(walletName, transactions) {
    const wallet = this.getWallet(walletName);
    if (!wallet) {
      throw new Error(`Wallet ${walletName} not found`);
    }

    const results = [];
    for (const tx of transactions) {
      const transaction = await wallet.sendTransaction({
        to: tx.to,
        value: ethers.parseEther(tx.value.toString()),
        gasLimit: tx.gasLimit || undefined
      });
      const receipt = await transaction.wait();
      results.push({
        transactionHash: receipt.hash,
        blockNumber: receipt.blockNumber,
        gasUsed: receipt.gasUsed.toString(),
        status: receipt.status
      });
    }
    return results;
  }

  listenToEvents(contractAddress, abi, eventName, callback) {
    const contract = new ethers.Contract(contractAddress, abi, this.provider);
    contract.on(eventName, (...args) => {
      callback(args);
    });
    return contract;
  }

  removeEventListener(contract, eventName) {
    contract.off(eventName);
  }
}

